parameters.jsonBody:
={
  "query": "query GetTranscript($transcriptId: String!) { transcript(id: $transcriptId) { id title date duration organizer_email participants { name email } sentences { text speaker_name } action_items summary { overview shorthand_bullet } } }",
  "variables": { "transcriptId": "{{ $json.body.meetingId || $json.body.transcriptId }}" }
}

values.content:
=Meeting Title: {{ $json.data.transcript.title }}
Date: {{ $json.data.transcript.date }}
Participants: {{ JSON.stringify($json.data.transcript.participants) }}
Summary: {{ $json.data.transcript.summary?.overview || 'No summary available' }}

Full Transcript:
{{ $json.data.transcript.sentences?.map(s => s.speaker_name + ': ' + s.text).join('\n') }}

=Meeting Analysis:
Client: {{ $json.client_name }} ({{ $json.client_company || 'Company not specified' }})
Email: {{ $json.client_email || 'Not found' }}
Meeting Date: {{ $json.meeting_date || 'Not specified' }}

Meeting Summary: {{ $json.meeting_summary }}

Key Points Discussed:
{{ $json.key_points?.join('\n- ') }}

Services Discussed:
{{ $json.services_discussed?.join('\n- ') }}

Client Pain Points:
{{ $json.client_pain_points?.join('\n- ') }}

Estimated Scope: {{ $json.estimated_scope || 'To be determined' }}

Follow-up Notes: {{ $json.follow_up_notes || 'None' }}

parameters.text:
